void badFunction() {
    // Noncompliant: allocated memory is never released
    int* ptr = (int*)malloc(sizeof(int) * 100);
    if (ptr) {
        for (int i = 0; i < 100; i++) {
            ptr[i] = i;
        }
    }
    // Memory leak! No free() call
}

void anotherBadFunction() {
    // Noncompliant: memory allocated but not released in all paths
    char* buffer = (char*)calloc(1024, sizeof(char));
    if (buffer) {
        if (someCondition()) {
            return; // Memory leak here!
        }
        free(buffer); // Only freed in one path
    }
}

compliant:
void goodFunction() {
    // Compliant: allocated memory is properly released
    int* ptr = (int*)malloc(sizeof(int) * 100);
    if (ptr) {
        for (int i = 0; i < 100; i++) {
            ptr[i] = i;
        }
        free(ptr); // Memory properly released
    }
}

void betterFunction() {
    // Compliant: using RAII with smart pointers
    auto ptr = std::make_unique<int[]>(100);
    for (int i = 0; i < 100; i++) {
        ptr[i] = i;
    }
    // Automatic cleanup
}

void modernFunction() {
    // Compliant: using containers instead of raw allocation
    std::vector<int> vec(100);
    for (int i = 0; i < 100; i++) {
        vec[i] = i;
    }
    // Automatic memory management
}
